mapper.update:
update model_connection_models m set test_status=#{testStatus}, tested_config_version=#{configVersion},
    last_test_at=#{testedAt}, enabled=case when #{testStatus}='PASSED' then m.enabled else false end, updated_at=#{testedAt}
from model_connections c where m.id=#{modelId} and m.connection_id=#{connectionId}
    and c.id=m.connection_id and c.config_version=#{configVersion} and c.status not in ('DISABLED','DELETED') and m.hidden_at is null

update model_connection_models m set enabled=#{enabled}, updated_at=#{updatedAt}
from model_connections c
where m.id=#{modelId} and m.connection_id=#{connectionId}
    and c.id=m.connection_id and c.config_version=#{configVersion}
    and c.status not in ('DISABLED','DELETED') and c.deleted_at is null and m.hidden_at is null
    and (not #{enabled} or (m.test_status='PASSED' and m.tested_config_version=#{configVersion}))
